/* =============================================
   Design System Variables
   ============================================= */
:root {
    /* Brand Colors */
    --color-primary-1: #FFCC00; /* bright yellow */
    --color-primary-2: #FF3B1F; /* saturated red-orange */

    --color-secondary-1: #00C8FF; /* bright cyan */
    --color-secondary-2: #0099DD; /* deeper cyan */

    --color-accent-1: #FFFFFF;  /* white */
    --color-accent-2: #F2A900;  /* warm golden border */

    --color-neutral-0: #000000; /* black */
    --color-neutral-1: #111111; /* near-black */
    --color-neutral-2: #F5F5F5; /* light gray */

    --color-success: #27AE60;
    --color-error: #E74C3C;
    --color-warning: #F1C40F;
    --color-info: #2980B9;

    /* Typography */
    --font-heading: 'Anton', Impact, Helvetica, sans-serif;
    --font-body: 'Source Sans 3', Arial, sans-serif;

    --font-size-h1: 3.25rem; /* ~52px */
    --font-size-h2: 2.5rem;  /* ~40px */
    --font-size-h3: 1.75rem; /* ~28px */
    --font-size-body: 1rem;  /* 16px */
    --font-size-small: 0.85rem; /* ~13-14px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (4px base) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    /* Layout */
    --header-height-desktop: 72px;
    --panel-radius: 14px;
    --panel-padding-x: 28px;
    --panel-padding-y: 24px;

    /* Effects */
    --shadow-strong: 0 18px 40px rgba(0, 0, 0, 0.75);
    --shadow-medium: 0 10px 24px rgba(0, 0, 0, 0.6);
    --shadow-soft: 0 4px 12px rgba(0, 0, 0, 0.5);
}

/* =============================================
   Global Layout & Background
   ============================================= */

*,
*::before,
*::after {
    box-sizing: border-box;
}

html,
body {
    height: 100%;
}

body.site-body {
    margin: 0;
    min-height: 100vh;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-accent-1);
    background:
        linear-gradient(to bottom, rgba(0, 0, 0, 0.35) 0%, rgba(0, 0, 0, 0.7) 45%, rgba(0, 0, 0, 0.85) 100%),
        url('beach-background.jpg') center center / cover no-repeat fixed;
    display: flex;
    flex-direction: column;
}

.site-backdrop {
    position: fixed;
    inset: 0;
    pointer-events: none;
    background: radial-gradient(circle at top center, rgba(255, 255, 255, 0.08) 0%, transparent 60%);
    z-index: -1;
}

.container {
    width: 100%;
    max-width: 1120px;
    margin: 0 auto;
    padding-inline: var(--space-4);
}

.site-main {
    flex: 1 0 auto;
    padding-top: var(--space-6);
    padding-bottom: var(--space-6);
}

/* =============================================
   Header & Navigation (Direct-Response Style)
   ============================================= */

.site-header {
    position: sticky;
    top: 0;
    z-index: 40;
    height: var(--header-height-desktop);
    background: linear-gradient(to bottom, rgba(0, 0, 0, 0.95), rgba(0, 0, 0, 0.88));
    box-shadow: var(--shadow-soft);
    border-bottom: 3px solid var(--color-primary-2);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 100%;
    gap: var(--space-4);
}

.brand-link {
    text-decoration: none;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
}

.brand-title {
    font-family: var(--font-heading);
    font-size: 1.6rem;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    background-image: linear-gradient(to bottom, var(--color-primary-1), var(--color-primary-1) 40%, var(--color-primary-2));
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    text-shadow: 0 3px 6px rgba(0, 0, 0, 0.9);
}

.brand-tagline {
    margin-top: 2px;
    font-size: 0.75rem;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: var(--color-secondary-1);
    text-shadow: 0 1px 3px rgba(0, 0, 0, 0.9);
}

.main-nav {
    font-size: 0.9rem;
}

.nav-list {
    list-style: none;
    display: flex;
    align-items: center;
    gap: var(--space-3);
    margin: 0;
    padding: 0;
    flex-wrap: wrap;
    justify-content: flex-end;
}

.nav-link {
    position: relative;
    text-decoration: none;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--color-accent-1);
    font-weight: 600;
    padding: 6px 0;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.9);
    transition: color 0.18s ease, transform 0.18s ease;
}

.nav-link::after {
    content: "";
    position: absolute;
    inset-inline: 0;
    bottom: -4px;
    height: 2px;
    background: linear-gradient(to right, var(--color-secondary-1), var(--color-secondary-2));
    opacity: 0;
    transform: scaleX(0.3);
    transform-origin: center;
    transition: opacity 0.18s ease, transform 0.18s ease;
}

.nav-link:hover,
.nav-link:focus-visible {
    color: var(--color-secondary-1);
    transform: translateY(-1px);
}

.nav-link:hover::after,
.nav-link:focus-visible::after {
    opacity: 1;
    transform: scaleX(1);
}

.nav-link-cta {
    padding-inline: 14px;
    padding-block: 6px;
    border-radius: 4px;
    background: linear-gradient(to bottom, var(--color-primary-1), var(--color-accent-2));
    color: #000;
    text-shadow: none;
    box-shadow: 0 4px 0 #c98a00, 0 8px 16px rgba(0, 0, 0, 0.6);
    border: 1px solid rgba(0, 0, 0, 0.9);
}

.nav-link-cta::after {
    display: none;
}

.nav-link-cta:hover,
.nav-link-cta:focus-visible {
    background: linear-gradient(to bottom, #ffe45a, var(--color-primary-1));
    transform: translateY(-1px);
    box-shadow: 0 5px 0 #c98a00, 0 10px 20px rgba(0, 0, 0, 0.75);
}

/* =============================================
   Footer
   ============================================= */

.site-footer {
    flex-shrink: 0;
    background: radial-gradient(circle at top center, rgba(255, 255, 255, 0.06) 0%, transparent 55%),
        linear-gradient(to bottom, rgba(0, 0, 0, 0.96), rgba(0, 0, 0, 0.98));
    color: var(--color-accent-1);
    padding-block: var(--space-5);
    box-shadow: 0 -8px 24px rgba(0, 0, 0, 0.8);
    border-top: 3px solid var(--color-primary-2);
}

.footer-inner {
    display: flex;
    flex-direction: column;
    gap: var(--space-4);
}

.footer-columns {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-5);
}

.footer-column {
    flex: 1 1 180px;
    min-width: 0;
}

.footer-heading {
    margin: 0 0 var(--space-2);
    font-family: var(--font-heading);
    font-size: 1rem;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: var(--color-secondary-1);
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.9);
}

.footer-links {
    list-style: none;
    padding: 0;
    margin: 0;
}

.footer-links li + li {
    margin-top: var(--space-1);
}

.footer-links a {
    font-size: var(--font-size-small);
    color: var(--color-accent-1);
    text-decoration: none;
    letter-spacing: 0.04em;
    text-transform: uppercase;
    opacity: 0.9;
    transition: color 0.18s ease, opacity 0.18s ease, transform 0.18s ease;
}

.footer-links a:hover,
.footer-links a:focus-visible {
    color: var(--color-secondary-1);
    opacity: 1;
    transform: translateX(2px);
}

.footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.08);
    padding-top: var(--space-3);
    display: flex;
    align-items: center;
    justify-content: center;
}

.footer-copy {
    margin: 0;
    font-size: 0.8rem;
    color: rgba(255, 255, 255, 0.75);
    letter-spacing: 0.08em;
    text-transform: uppercase;
}

/* =============================================
   Generic Typography Helpers
   ============================================= */

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--font-heading);
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-top: 0;
    color: var(--color-accent-1);
}

h1 {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

h2 {
    font-size: var(--font-size-h2);
    line-height: var(--line-height-tight);
}

h3 {
    font-size: var(--font-size-h3);
    line-height: var(--line-height-tight);
}

p {
    margin-top: 0;
    margin-bottom: var(--space-3);
}

/* =============================================
   Responsive Adjustments
   ============================================= */

@media (max-width: 960px) {
    .header-inner {
        gap: var(--space-3);
    }

    .brand-title {
        font-size: 1.4rem;
    }

    .brand-tagline {
        display: none; /* tighten header on tablets/phones */
    }

    .site-main {
        padding-top: var(--space-5);
        padding-bottom: var(--space-5);
    }
}

@media (max-width: 720px) {
    .site-header {
        height: auto;
        padding-block: var(--space-2);
    }

    .header-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav-list {
        justify-content: flex-start;
        gap: var(--space-2);
    }

    .nav-link {
        font-size: 0.8rem;
    }

    .site-footer {
        padding-block: var(--space-4);
    }

    .footer-columns {
        flex-direction: column;
        gap: var(--space-4);
    }

    .footer-heading {
        font-size: 0.9rem;
    }
}

@media (max-width: 480px) {
    .container {
        padding-inline: var(--space-3);
    }

    .brand-title {
        font-size: 1.25rem;
    }

    .nav-link-cta {
        padding-inline: 10px;
    }
}
